import{_ as a,o,c as r,aA as t}from"./chunks/framework.Bs_9x8Eu.js";const h=JSON.parse('{"title":"Publications and software using AIBECS","description":"","frontmatter":{},"headers":[],"relativePath":"publications/1_publications.md","filePath":"publications/1_publications.md","lastUpdated":null}'),i={name:"publications/1_publications.md"};function n(l,e,s,c,d,p){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="publications" tabindex="-1">Publications and software using AIBECS <a class="header-anchor" href="#publications" aria-label="Permalink to &quot;Publications and software using AIBECS {#publications}&quot;">​</a></h1><p>This page collects papers and software that use AIBECS, plus related projects in the same ecosystem. It is community-driven — if your work uses AIBECS and is missing here, please open a pull request (see <a href="/AIBECS.jl/previews/PR119/publications/1_publications#how-to-add-your-work">How to add your work</a> below).</p><h2 id="Software-citation" tabindex="-1">Software citation <a class="header-anchor" href="#Software-citation" aria-label="Permalink to &quot;Software citation {#Software-citation}&quot;">​</a></h2><p>This code is © Benoît Pasquier (2026) and contributors, and it is made available under the MIT license enclosed with the software.</p><p>Over and above the legal restrictions imposed by this license, if you use AIBECS for an academic publication then you are obliged to provide proper attribution. This can be to this code directly,</p><blockquote><p>Benoît Pasquier, François W. Primeau, and Seth G. John (2026). <strong>AIBECS.jl: A tool for exploring global marine biogeochemical cycles</strong>. <em>Zenodo</em>. doi: <a href="https://doi.org/10.5281/zenodo.2864051" target="_blank" rel="noreferrer">10.5281/zenodo.2864051</a>.</p></blockquote><p>or to the paper that describes it,</p><blockquote><p>Pasquier, B., Primeau, F. W., and John, S. G. (2022). <strong>AIBECS.jl: A tool for exploring global marine biogeochemical cycles</strong>. <em>Journal of Open Source Software</em>, 7(69), 3814. doi: <a href="https://doi.org/10.21105/joss.03814" target="_blank" rel="noreferrer">10.21105/joss.03814</a>.</p></blockquote><p>but, ideally, both. BibTeX entries live in <a href="https://github.com/JuliaOcean/AIBECS.jl/blob/main/CITATION.bib" target="_blank" rel="noreferrer"><code>CITATION.bib</code></a> under the keys <code>AIBECS.jl</code> and <code>Pasquier_etal_JOSS_2022</code>. If you also use data provided by AIBECS (such as the OCIM circulations), please cite those datasets as well.</p><h2 id="Papers-using-AIBECS" tabindex="-1">Papers using AIBECS <a class="header-anchor" href="#Papers-using-AIBECS" aria-label="Permalink to &quot;Papers using AIBECS {#Papers-using-AIBECS}&quot;">​</a></h2><p>This list is curated by the maintainer; please add your own work via PR.</p><ul><li><p><strong>Du, J., Haley, B. A., McManus, J., Blaser, P., Rickli, J., &amp; Vance, D. (2025).</strong> Abyssal seafloor as a key driver of ocean trace-metal biogeochemical cycles. <em>Nature</em>, 642(8068), 620–627. <a href="https://doi.org/10.1038/s41586-025-09038-3" target="_blank" rel="noreferrer">doi:10.1038/s41586-025-09038-3</a></p></li><li><p><strong>Liang, Z., Letscher, R. T., &amp; Knapp, A. N. (2025).</strong> Oligotrophic ocean new production supported by lateral transport of dissolved organic nutrients. <em>Global Biogeochemical Cycles</em>, 39(6). <a href="https://doi.org/10.1029/2024GB008345" target="_blank" rel="noreferrer">doi:10.1029/2024GB008345</a></p></li><li><p><strong>John, S. G., Liang, H., Pasquier, B., Holzer, M., &amp; Silva, S. (2024).</strong> Biogeochemical fluxes of nickel in the global oceans inferred from a diagnostic model. <em>Global Biogeochemical Cycles</em>, 38(5). <a href="https://doi.org/10.1029/2023GB008018" target="_blank" rel="noreferrer">doi:10.1029/2023GB008018</a></p></li><li><p><strong>Du, J. (2023).</strong> SedTrace 1.0: a Julia-based framework for generating and running reactive-transport models of marine sediment diagenesis specializing in trace elements and isotopes. <em>Geoscientific Model Development</em>, 16(20), 5865–5894. <a href="https://doi.org/10.5194/gmd-16-5865-2023" target="_blank" rel="noreferrer">doi:10.5194/gmd-16-5865-2023</a></p></li><li><p><strong>Pasquier, B., Hines, S. K. V., Liang, H., Wu, Y., Goldstein, S. L., &amp; John, S. G. (2022).</strong> GNOM v1.0: an optimized steady-state model of the modern marine neodymium cycle. <em>Geoscientific Model Development</em>, 15(11), 4625–4656. <a href="https://doi.org/10.5194/gmd-15-4625-2022" target="_blank" rel="noreferrer">doi:10.5194/gmd-15-4625-2022</a></p></li><li><p><strong>Pasquier, B., Primeau, F. W., &amp; John, S. G. (2022).</strong> AIBECS.jl: A tool for exploring global marine biogeochemical cycles. <em>Journal of Open Source Software</em>, 7(69), 3814. <a href="https://doi.org/10.21105/joss.03814" target="_blank" rel="noreferrer">doi:10.21105/joss.03814</a></p></li></ul><h2 id="Related-software" tabindex="-1">Related software <a class="header-anchor" href="#Related-software" aria-label="Permalink to &quot;Related software {#Related-software}&quot;">​</a></h2><ul><li><p><a href="https://github.com/MTEL-USC/GNOM" target="_blank" rel="noreferrer">GNOM</a> — optimised steady-state model of the modern marine neodymium cycle, built on AIBECS. Software DOI: <a href="https://doi.org/10.5281/zenodo.5651295" target="_blank" rel="noreferrer">10.5281/zenodo.5651295</a>.</p></li><li><p><a href="https://github.com/briochemc/OceanCirculations" target="_blank" rel="noreferrer">OceanCirculations.jl</a> — collection of ocean transport matrices distributed via DataDeps; in the near future, this and <code>OceanGrids.jl</code> may be bundled directly into AIBECS rather than living in separate repos.</p></li><li><p><a href="https://github.com/briochemc/OceanGrids" target="_blank" rel="noreferrer">OceanGrids.jl</a> — grid abstractions used throughout AIBECS; same near-future-bundling note.</p></li><li><p><a href="https://github.com/ggebbie/OceanGreensFunctionMethods.jl" target="_blank" rel="noreferrer">OceanGreensFunctionMethods.jl</a> — Julia implementation of Green&#39;s-function tracer-pathway methods, including the pedagogical 9-box model surfaced in AIBECS as <code>Haine_and_Hall_2025</code>.</p></li></ul><h2 id="How-to-add-your-work" tabindex="-1">How to add your work <a class="header-anchor" href="#How-to-add-your-work" aria-label="Permalink to &quot;How to add your work {#How-to-add-your-work}&quot;">​</a></h2><p>If your published paper or software uses AIBECS:</p><ol><li><p>Open a pull request adding an entry to the relevant list above (alphabetised within section by year, newest first).</p></li><li><p>Append the corresponding BibTeX entry to <a href="https://github.com/JuliaOcean/AIBECS.jl/blob/main/CITATION.bib" target="_blank" rel="noreferrer"><code>CITATION.bib</code></a>. Use a descriptive citekey (e.g. <code>Author_etal_Journal_Year</code>) and place the entry under the <em>Papers using AIBECS</em> section.</p></li><li><p>Briefly describe the role AIBECS played in your work in the PR description so the maintainer can sanity-check the categorisation.</p></li></ol>',17)])])}const b=a(i,[["render",n]]);export{h as __pageData,b as default};
